SELECT DISTINCT region
FROM covid_data
WHERE data_type = 'daily';

SELECT c.*
FROM covid_data c
INNER JOIN stages s ON c.region = s.region_id AND c.subregion = s.subregion_id;

SELECT region
FROM (
    SELECT region, AVG(deaths) AS avg_deaths
    FROM covid_data
    GROUP BY region
) AS region_deaths
WHERE avg_deaths > (
    SELECT AVG(deaths)
    FROM covid_data
);
